SELECT ?episode_label WHERE {
  ?series rdfs:label "Death March to Parallel World Rhapsody"@en .
  ?episode wdt:P361 ?series .
  ?episode wdt:P1201 5 .
  ?episode rdfs:label ?episode_label
}

